function validateDamagesAgainstPolicy(damages: Step[], policyItems: Step[]): void {
  const policyItemTypes = policyItems.map((i: any) => i.type);
  for (const damage of damages) {
    if (!policyItemTypes.includes(damage.itemType)) {
      throw new Error(`Damage references item not in policy: ${damage.itemType}`);
    }
  }
  const policyCounts: Record<string, number> = {};
  for (const item of policyItems) {
    policyCounts[item.type] = (policyCounts[item.type] || 0) + 1;
  }
  const damageCounts: Record<string, number> = {};
  for (const damage of damages) {
    damageCounts[damage.itemType] = (damageCounts[damage.itemType] || 0) + 1;
  }
  for (const type of Object.keys(damageCounts)) {
    if (damageCounts[type] > (policyCounts[type] || 0)) {
      throw new Error(`More damages of type ${type} than insured`);
    }
  }
}
